"use client";

import { FormEvent, useState } from "react";
import { siteConfig } from "@/lib/site-config";

export function ContactForm() {
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [message, setMessage] = useState("");

  function handleSubmit(e: FormEvent) {
    e.preventDefault();
    const text = [
      `Hello ${siteConfig.businessName},`,
      name && `Name: ${name}`,
      phone && `Phone: ${phone}`,
      message && `Message: ${message}`,
    ]
      .filter(Boolean)
      .join("\n");
    const url = `${siteConfig.whatsappUrl}?text=${encodeURIComponent(text)}`;
    window.open(url, "_blank", "noopener,noreferrer");
  }

  return (
    <form
      onSubmit={handleSubmit}
      className="rounded-2xl border border-brand-border bg-white p-6 shadow-sm"
    >
      <h2 className="font-serif text-xl font-semibold text-brand-ink">Message on WhatsApp</h2>
      <p className="mt-1 text-sm text-brand-muted">
        We’ll open WhatsApp with your details filled in—no server, works on mobile and desktop.
      </p>
      <div className="mt-6 space-y-4">
        <label className="block text-sm font-medium text-brand-ink">
          Name
          <input
            className="mt-1 w-full rounded-xl border border-brand-border bg-brand-bg px-3 py-2 text-brand-ink outline-none ring-brand-accent/30 focus:ring-2"
            value={name}
            onChange={(e) => setName(e.target.value)}
            autoComplete="name"
          />
        </label>
        <label className="block text-sm font-medium text-brand-ink">
          Phone
          <input
            className="mt-1 w-full rounded-xl border border-brand-border bg-brand-bg px-3 py-2 text-brand-ink outline-none ring-brand-accent/30 focus:ring-2"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
            inputMode="tel"
            autoComplete="tel"
            placeholder={siteConfig.phoneDisplay}
          />
        </label>
        <label className="block text-sm font-medium text-brand-ink">
          Message
          <textarea
            className="mt-1 min-h-[120px] w-full rounded-xl border border-brand-border bg-brand-bg px-3 py-2 text-brand-ink outline-none ring-brand-accent/30 focus:ring-2"
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="What would you like stitched or altered?"
          />
        </label>
      </div>
      <div className="mt-6 flex flex-col gap-3 sm:flex-row sm:items-center">
        <button
          type="submit"
          className="inline-flex flex-1 items-center justify-center rounded-full bg-[#25D366] px-5 py-3 text-sm font-semibold text-white shadow transition hover:brightness-95"
        >
          Open WhatsApp
        </button>
        <a
          href={`mailto:${siteConfig.email}?subject=${encodeURIComponent(`Enquiry for ${siteConfig.businessName}`)}`}
          className="text-center text-sm font-medium text-brand-accent hover:underline"
        >
          Prefer email?
        </a>
      </div>
    </form>
  );
}
